const loginForm=document.getElementById("loginForm");loginForm&&loginForm.addEventListener("submit",function(e){e.preventDefault();let t=document.getElementById("loginEmail").value.trim(),n=document.getElementById("loginPassword").value,l=document.getElementById("loginMessage"),o=JSON.parse(localStorage.getItem("users"))||[],i=o.find(e=>e.email===t&&e.password===n);if(!i){l.style.color="red",l.textContent="Invalid email or password.";return}localStorage.setItem("loggedInUser",JSON.stringify(i)),l.style.color="green",l.textContent="Login Successful! Redirecting...",setTimeout(()=>{window.location.href="index.html"},1500)});